#include <XSegment_lib.h>

XSeg_TM1637 display(2, 3);

void setup() {
  Serial.begin(115200);
  display.begin();
  display.setBrightness(7);

  // Demo sequence
  Serial.println("=== TM1637 Demo ===");
}

void loop() {
  // Integer test
  static int counter = 0;
  display.show(counter);
  Serial.print("Display: "); Serial.println(counter);
  counter = (counter + 1) % 10000;

  delay(500);

  // Switch to string
  display.show("HELP");
  Serial.println("Display: HELP");
  delay(500);

  // Float
  display.show(3.141f, 2);
  Serial.println("Display: 3.14");
  delay(500);
}
